import{_ as e,o as l,c as n,ag as a}from"./chunks/framework.DGzMGr_a.js";const c=JSON.parse('{"title":"FMEA 失效模式与影响分析","description":"","frontmatter":{},"headers":[],"relativePath":"tools/fmea.md","filePath":"tools/fmea.md","lastUpdated":1782656455000}'),r={name:"tools/fmea.md"};function d(s,t,i,g,o,x){return l(),n("div",null,[...t[0]||(t[0]=[a('<h1 id="fmea-失效模式与影响分析" tabindex="-1">FMEA 失效模式与影响分析 <a class="header-anchor" href="#fmea-失效模式与影响分析" aria-label="Permalink to &quot;FMEA 失效模式与影响分析&quot;">​</a></h1><p>FMEA（Failure Mode and Effects Analysis，失效模式与影响分析）是一种<strong>预防性的可靠性分析工具</strong>，在产品设计或过程开发的早期阶段，系统化识别潜在的失效模式、分析其后果和原因，并在失效发生之前采取预防措施。</p><h2 id="dfmea-与-pfmea" tabindex="-1">DFMEA 与 PFMEA <a class="header-anchor" href="#dfmea-与-pfmea" aria-label="Permalink to &quot;DFMEA 与 PFMEA&quot;">​</a></h2><p>FMEA 根据应用阶段分为两大类：</p><table tabindex="0"><thead><tr><th style="text-align:center;">类型</th><th style="text-align:left;">全称</th><th style="text-align:left;">应用阶段</th><th style="text-align:left;">分析对象</th><th style="text-align:left;">目标</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>DFMEA</strong></td><td style="text-align:left;">设计 FMEA (Design FMEA)</td><td style="text-align:left;">产品设计阶段</td><td style="text-align:left;">产品设计缺陷</td><td style="text-align:left;">预防产品功能失效</td></tr><tr><td style="text-align:center;"><strong>PFMEA</strong></td><td style="text-align:left;">过程 FMEA (Process FMEA)</td><td style="text-align:left;">工艺/过程设计阶段</td><td style="text-align:left;">制造/装配过程</td><td style="text-align:left;">预防过程缺陷产生</td></tr></tbody></table><p><strong>DFMEA 关注&quot;设计是否合理&quot;</strong>——分析产品在预期使用条件下可能出现的功能失效，如零件断裂、密封泄漏、电路短路等。<strong>PFMEA 关注&quot;过程是否可靠&quot;</strong>——分析制造过程中可能导致产品缺陷的环节，如定位不准、参数偏差、操作遗漏等。</p><h2 id="严重度-s-、频度-o-、探测度-d-评级" tabindex="-1">严重度 (S)、频度 (O)、探测度 (D) 评级 <a class="header-anchor" href="#严重度-s-、频度-o-、探测度-d-评级" aria-label="Permalink to &quot;严重度 (S)、频度 (O)、探测度 (D) 评级&quot;">​</a></h2><p>FMEA 的核心是三项风险因子的量化评级，各维度均为 <strong>1~10 分</strong>：</p><h3 id="严重度-severity-s" tabindex="-1">严重度 (Severity, S) <a class="header-anchor" href="#严重度-severity-s" aria-label="Permalink to &quot;严重度 (Severity, S)&quot;">​</a></h3><p>评估失效模式对客户或系统的影响严重程度：</p><table tabindex="0"><thead><tr><th style="text-align:center;">等级</th><th style="text-align:center;">严重度</th><th style="text-align:left;">DFMEA 描述</th><th style="text-align:left;">PFMEA 描述</th></tr></thead><tbody><tr><td style="text-align:center;">1</td><td style="text-align:center;">无影响</td><td style="text-align:left;">不影响功能</td><td style="text-align:left;">无影响或轻微不便</td></tr><tr><td style="text-align:center;">2~3</td><td style="text-align:center;">轻微</td><td style="text-align:left;">轻微功能降级</td><td style="text-align:left;">轻微外观/操作不便</td></tr><tr><td style="text-align:center;">4~6</td><td style="text-align:center;">中等</td><td style="text-align:left;">功能部分丧失</td><td style="text-align:left;">导致部分返工或生产中断</td></tr><tr><td style="text-align:center;">7~8</td><td style="text-align:center;">高</td><td style="text-align:left;">功能丧失，安全受影响</td><td style="text-align:left;">产品报废或产线停线</td></tr><tr><td style="text-align:center;">9~10</td><td style="text-align:center;">极高</td><td style="text-align:left;">安全隐患，违反法规</td><td style="text-align:left;">可能导致人员伤害或法规违反</td></tr></tbody></table><h3 id="频度-occurrence-o" tabindex="-1">频度 (Occurrence, O) <a class="header-anchor" href="#频度-occurrence-o" aria-label="Permalink to &quot;频度 (Occurrence, O)&quot;">​</a></h3><p>评估失效原因发生的可能性：</p><table tabindex="0"><thead><tr><th style="text-align:center;">等级</th><th style="text-align:center;">发生概率</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:center;">1</td><td style="text-align:center;">极低</td><td style="text-align:left;">几乎不会发生（≤ 1/1,500,000）</td></tr><tr><td style="text-align:center;">2~3</td><td style="text-align:center;">低</td><td style="text-align:left;">较少发生</td></tr><tr><td style="text-align:center;">4~6</td><td style="text-align:center;">中等</td><td style="text-align:left;">偶尔发生</td></tr><tr><td style="text-align:center;">7~8</td><td style="text-align:center;">高</td><td style="text-align:left;">频繁发生</td></tr><tr><td style="text-align:center;">9~10</td><td style="text-align:center;">极高</td><td style="text-align:left;">几乎必然发生（≥ 1/10）</td></tr></tbody></table><h3 id="探测度-detection-d" tabindex="-1">探测度 (Detection, D) <a class="header-anchor" href="#探测度-detection-d" aria-label="Permalink to &quot;探测度 (Detection, D)&quot;">​</a></h3><p>评估现有控制措施在失效发生前或发生后（流到客户前）探测到的能力：</p><table tabindex="0"><thead><tr><th style="text-align:center;">等级</th><th style="text-align:center;">探测能力</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:center;">1</td><td style="text-align:center;">几乎确定</td><td style="text-align:left;">现有控制一定能检测到失效</td></tr><tr><td style="text-align:center;">2~3</td><td style="text-align:center;">高</td><td style="text-align:left;">探测手段有很高的检出率</td></tr><tr><td style="text-align:center;">4~6</td><td style="text-align:center;">中等</td><td style="text-align:left;">探测手段可能检测到</td></tr><tr><td style="text-align:center;">7~8</td><td style="text-align:center;">低</td><td style="text-align:left;">探测手段效果有限</td></tr><tr><td style="text-align:center;">9~10</td><td style="text-align:center;">几乎不可能</td><td style="text-align:left;">无法或极难检测到失效</td></tr></tbody></table><h2 id="rpn-风险优先数" tabindex="-1">RPN (风险优先数) <a class="header-anchor" href="#rpn-风险优先数" aria-label="Permalink to &quot;RPN (风险优先数)&quot;">​</a></h2><p><strong>RPN = S × O × D</strong></p><p>RPN 取值范围 1 ~ 1000，数值越高代表失效风险越大，需要优先采取改善措施。</p><blockquote><p><strong>注意</strong>：AIAG &amp; VDA 新版 FMEA 手册建议使用 <strong>AP（行动优先级）</strong> 替代传统的 RPN 阈值法，通过 S、O、D 的组合直接判定行动的优先等级——高 (H)、中 (M)、低 (L)，避免 S=9、O=3、D=3（RPN=81）与 S=5、O=5、D=4（RPN=100）之间的误判。</p></blockquote><h2 id="fmea-实施-10-步骤" tabindex="-1">FMEA 实施 10 步骤 <a class="header-anchor" href="#fmea-实施-10-步骤" aria-label="Permalink to &quot;FMEA 实施 10 步骤&quot;">​</a></h2><p>根据 AIAG &amp; VDA FMEA 手册（2019），实施流程分为以下 10 个步骤：</p><table tabindex="0"><thead><tr><th style="text-align:center;">步骤</th><th style="text-align:left;">内容</th><th style="text-align:left;">输出</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>1</strong></td><td style="text-align:left;"><strong>项目规划与准备</strong> — 确定项目范围、团队、分析边界</td><td style="text-align:left;">FMEA 项目计划</td></tr><tr><td style="text-align:center;"><strong>2</strong></td><td style="text-align:left;"><strong>结构分析</strong> — 对系统/过程进行结构分解（框图/过程流程图）</td><td style="text-align:left;">结构树、过程流程图</td></tr><tr><td style="text-align:center;"><strong>3</strong></td><td style="text-align:left;"><strong>功能分析</strong> — 识别每个结构要素的功能要求</td><td style="text-align:left;">功能矩阵、功能树</td></tr><tr><td style="text-align:center;"><strong>4</strong></td><td style="text-align:left;"><strong>失效分析</strong> — 识别潜在的失效模式、影响和原因</td><td style="text-align:left;">失效网、失效链</td></tr><tr><td style="text-align:center;"><strong>5</strong></td><td style="text-align:left;"><strong>风险分析</strong> — 评估 S、O、D，计算 RPN 或判定 AP</td><td style="text-align:left;">风险评级表</td></tr><tr><td style="text-align:center;"><strong>6</strong></td><td style="text-align:left;"><strong>优化</strong> — 制定预防和探测措施</td><td style="text-align:left;">改善措施清单</td></tr><tr><td style="text-align:center;"><strong>7</strong></td><td style="text-align:left;"><strong>措施跟踪</strong> — 跟踪措施执行状态和效果</td><td style="text-align:left;">措施跟踪表</td></tr><tr><td style="text-align:center;"><strong>8</strong></td><td style="text-align:left;"><strong>结果文件化</strong> — 将分析结果整理归档</td><td style="text-align:left;">FMEA 报告</td></tr><tr><td style="text-align:center;"><strong>9</strong></td><td style="text-align:left;"><strong>动态更新</strong> — 根据变更和持续改进更新 FMEA</td><td style="text-align:left;">更新记录</td></tr><tr><td style="text-align:center;"><strong>10</strong></td><td style="text-align:left;"><strong>经验总结</strong> — 将知识沉淀到企业数据库</td><td style="text-align:left;">经验库 / Lesson Learned</td></tr></tbody></table><h2 id="降低风险的行动优先级" tabindex="-1">降低风险的行动优先级 <a class="header-anchor" href="#降低风险的行动优先级" aria-label="Permalink to &quot;降低风险的行动优先级&quot;">​</a></h2><p>采取纠正措施的优先级策略：</p><ol><li><strong>设计变更（最高优先级）</strong> — 从根源消除失效模式（如更改材料、修改结构）</li><li><strong>防错/自动化（高优先级）</strong> — 通过防错装置（Poka-Yoke）或自动化检测防止失效发生</li><li><strong>过程改进（中优先级）</strong> — 优化工艺参数、增加 SPC 监控点</li><li><strong>增加探测手段（低优先级）</strong> — 增加检查频次、升级检测设备</li></ol><p>FMEA 不仅是质量工具，更是一种<strong>系统化预防思维</strong>的体现。在企业中推行 FMEA 时，关键在于跨部门团队的充分协作，以及对历史失效数据的有效积累和利用。</p><h2 id="fmea-应用的常见误区" tabindex="-1">FMEA 应用的常见误区 <a class="header-anchor" href="#fmea-应用的常见误区" aria-label="Permalink to &quot;FMEA 应用的常见误区&quot;">​</a></h2><ol><li><strong>一次性完成，过后不更新</strong> — FMEA 应随设计变更、过程变更和客诉反馈持续动态更新，而非仅在项目初期做完即束之高阁</li><li><strong>RPN 阈值一刀切</strong> — 机械地设定 RPN ≥ 100 才采取行动，可能忽视 S=9、O=2、D=2（RPN=36）的严重安全隐患；建议结合 AP 判定综合决策</li><li><strong>仅由质量部门独立编写</strong> — FMEA 需要设计、工艺、制造、质量、供应商等多职能团队共同参与，单一视角会遗漏大量潜在失效模式</li><li><strong>将 PFMEA 写成检验清单</strong> — PFMEA 应关注预防和探测失效的<strong>过程控制手段</strong>，而非简单地罗列检查项目</li><li><strong>忽略历史失效数据</strong> — 同类产品的售后客诉、退货分析和现场故障数据是 FMEA 最宝贵的信息来源，务必纳入分析</li></ol><h2 id="fmea-与-iatf-16949-的关联" tabindex="-1">FMEA 与 IATF 16949 的关联 <a class="header-anchor" href="#fmea-与-iatf-16949-的关联" aria-label="Permalink to &quot;FMEA 与 IATF 16949 的关联&quot;">​</a></h2><p>FMEA 是 IATF 16949 质量管理体系的核心要求之一，也是 APQP（先期产品质量策划）和 PPAP（生产件批准程序）的必备输入。在 AIAG &amp; VDA 新版手册的推动下，FMEA 的方法论正在向更结构化的七步法演进，强调功能分析、失效网和措施跟踪的闭环管理。掌握 FMEA，是质量工程师从&quot;救火型&quot;转向&quot;预防型&quot;的关键能力跃迁。</p>',32)])])}const h=e(r,[["render",d]]);export{c as __pageData,h as default};
